import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

const INSTRUCTOR = { roles: ['instructor'] as const };

/**
 * LearnLoop route tree. Hash routing is configured in app.config.ts.
 * Login/signup render standalone; everything else is wrapped by LayoutComponent.
 * Public browse routes (catalog + course detail) live inside the layout WITHOUT
 * a guard. Each route carries `data.flow { node, edgesTo, ... }` for the flow map.
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['catalog', 'signup', 'instructor'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['catalog', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    children: [
      // ---- Public browse ----
      {
        path: '',
        pathMatch: 'full',
        loadComponent: () =>
          import('./pages/catalog/catalog.component').then((m) => m.CatalogComponent),
        data: { flow: { node: 'catalog', showInNavbar: true, edgesTo: ['course-detail', 'my-courses'] } },
      },
      {
        path: 'courses/:id',
        loadComponent: () =>
          import('./pages/course-detail/course-detail.component').then((m) => m.CourseDetailComponent),
        data: { flow: { node: 'course-detail', edgesTo: ['catalog', 'lesson-viewer', 'quiz-take', 'login'] } },
      },

      // ---- Learner (any logged-in user) ----
      {
        path: 'courses/:id/lessons/:lessonId',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/lesson-viewer/lesson-viewer.component').then((m) => m.LessonViewerComponent),
        data: { flow: { node: 'lesson-viewer', scope: 'student', edgesTo: ['course-detail', 'quiz-take'] } },
      },
      {
        path: 'quizzes/:id',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/quiz-take/quiz-take.component').then((m) => m.QuizTakeComponent),
        data: { flow: { node: 'quiz-take', scope: 'student', edgesTo: ['course-detail'] } },
      },
      {
        path: 'my-courses',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/my-courses/my-courses.component').then((m) => m.MyCoursesComponent),
        data: { flow: { node: 'my-courses', showInNavbar: true, scope: 'student', edgesTo: ['course-detail', 'catalog'] } },
      },

      // ---- Instructor ----
      {
        path: 'instructor',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/instructor-dashboard/instructor-dashboard.component').then(
            (m) => m.InstructorDashboardComponent,
          ),
        data: { roles: INSTRUCTOR.roles, flow: { node: 'instructor', showInNavbar: true, scope: 'instructor', edgesTo: ['instructor-course-editor', 'gradebook'] } },
      },
      {
        path: 'instructor/courses/:id',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/instructor-course-editor/instructor-course-editor.component').then(
            (m) => m.InstructorCourseEditorComponent,
          ),
        data: { roles: INSTRUCTOR.roles, flow: { node: 'instructor-course-editor', scope: 'instructor', edgesTo: ['instructor', 'gradebook'] } },
      },
      {
        path: 'instructor/courses/:id/gradebook',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/gradebook/gradebook.component').then((m) => m.GradebookComponent),
        data: { roles: INSTRUCTOR.roles, flow: { node: 'gradebook', scope: 'instructor', edgesTo: ['instructor-course-editor', 'instructor'] } },
      },
      {
        path: 'admin/settings',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-settings/admin-settings.component').then(
            (m) => m.AdminSettingsComponent,
          ),
        data: { roles: INSTRUCTOR.roles, flow: { node: 'admin-settings', showInNavbar: true, scope: 'instructor', edgesTo: ['instructor'] } },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
